CREATE OR REPLACE FUNCTION fpb_dep_get_print_code ( as_slip_no char ) RETURNS varchar AS $body$
DECLARE

ls_print_code sc_dep_m_ucf_dep_item_type.print_code%type;

BEGIN
  select  min( distinct  sc_dep_m_ucf_dep_item_type.print_code)
  into STRICT ls_print_code
  from sc_dep_m_ucf_dep_item_type
  ,sc_dep_m_creditor_item
  where  sc_dep_m_creditor_item.item_type = sc_dep_m_ucf_dep_item_type.deposit_item_type
  and  sc_dep_m_creditor_item.refer_to_deposit_doc_no = as_slip_no
  and sc_dep_m_ucf_dep_item_type.print_code not in ( 'INT' ,'TAX' ,'WCI' )
  and ( sc_dep_m_ucf_dep_item_type.sign_flag <> 0 )
;

  RETURN ls_print_code;
END;
$body$
